/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements NotificationAdapter so it can be registered with
 * NotificationService for the 'email' channel.
 *
 * Features:
 * - Template rendering per notification type
 * - Recipient resolution (validates email format)
 * - Configurable sender and transport
 * - In-memory transport for testing; swap for real provider in production
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  from: string;
  to: string;
  subject: string;
  html: string;
  text: string;
  sentAt: Date;
}

export interface EmailTransport {
  sendMail(message: EmailMessage): Promise<{ success: boolean; error?: string }>;
}

export interface EmailAdapterConfig {
  defaultFrom: string;
  transport?: EmailTransport;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  defaultFrom: 'noreply@taskflowpro.com',
};

/**
 * In-memory transport that stores emails for inspection.
 * Used when no external transport is provided.
 */
export class InMemoryTransport implements EmailTransport {
  private messages: EmailMessage[] = [];

  async sendMail(message: EmailMessage): Promise<{ success: boolean; error?: string }> {
    this.messages.push(message);
    return { success: true };
  }

  getMessages(): EmailMessage[] {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

interface RenderedTemplate {
  subject: string;
  html: string;
  text: string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function resolveRecipient(recipient: string): { valid: boolean; email: string; error?: string } {
  const trimmed = recipient.trim();
  if (!trimmed) {
    return { valid: false, email: '', error: 'Recipient is empty' };
  }
  if (!EMAIL_REGEX.test(trimmed)) {
    return { valid: false, email: trimmed, error: `Invalid email address: ${trimmed}` };
  }
  return { valid: true, email: trimmed };
}

function renderTemplate(payload: NotificationPayload): RenderedTemplate {
  const templateRenderers: Record<NotificationType, (p: NotificationPayload) => RenderedTemplate> = {
    'order:confirmation': renderOrderConfirmation,
    'order:status-update': renderOrderStatusUpdate,
    'user:welcome': renderUserWelcome,
    'user:profile-updated': renderUserProfileUpdated,
  };

  const renderer = templateRenderers[payload.type];
  return renderer(payload);
}

function renderOrderConfirmation(payload: NotificationPayload): RenderedTemplate {
  const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
  return {
    subject: payload.subject,
    html: `<h1>Order Confirmation</h1>
<p>Thank you for your order <strong>${orderId}</strong>.</p>
<p>${payload.body}</p>
<p>We will notify you when your order status changes.</p>`,
    text: `Order Confirmation\n\nThank you for your order ${orderId}.\n${payload.body}\nWe will notify you when your order status changes.`,
  };
}

function renderOrderStatusUpdate(payload: NotificationPayload): RenderedTemplate {
  const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
  const newStatus = (payload.metadata?.newStatus as string) ?? 'unknown';
  return {
    subject: payload.subject,
    html: `<h1>Order Update</h1>
<p>Your order <strong>${orderId}</strong> is now <strong>${newStatus}</strong>.</p>
<p>${payload.body}</p>`,
    text: `Order Update\n\nYour order ${orderId} is now ${newStatus}.\n${payload.body}`,
  };
}

function renderUserWelcome(payload: NotificationPayload): RenderedTemplate {
  return {
    subject: payload.subject,
    html: `<h1>Welcome to TaskFlow Pro!</h1>
<p>${payload.body}</p>
<p>Get started by creating your first order.</p>`,
    text: `Welcome to TaskFlow Pro!\n\n${payload.body}\nGet started by creating your first order.`,
  };
}

function renderUserProfileUpdated(payload: NotificationPayload): RenderedTemplate {
  return {
    subject: payload.subject,
    html: `<h1>Profile Updated</h1>
<p>${payload.body}</p>`,
    text: `Profile Updated\n\n${payload.body}`,
  };
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private transport: EmailTransport;
  private sentEmails: Array<{ to: string; subject: string; body: string; sentAt: Date }> = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemoryTransport();
  }

  /**
   * Send a notification as an email.
   *
   * Steps:
   * 1. Resolve and validate the recipient email address
   * 2. Render the notification body using the appropriate template
   * 3. Send via the configured transport
   *
   * Must not throw — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Resolve recipient
      const recipient = resolveRecipient(payload.recipient);
      if (!recipient.valid) {
        this.logger.warn(`Invalid recipient: ${recipient.error}`);
        return { success: false, channel: 'email', error: recipient.error };
      }

      // 2. Render template
      const rendered = renderTemplate(payload);

      // 3. Build and send email message
      const message: EmailMessage = {
        from: this.config.defaultFrom,
        to: recipient.email,
        subject: rendered.subject,
        html: rendered.html,
        text: rendered.text,
        sentAt: new Date(),
      };

      this.logger.info(`Sending email to ${recipient.email}: ${rendered.subject}`);

      const result = await this.transport.sendMail(message);

      // Track for backwards-compatible getSentEmails()
      if (result.success) {
        this.sentEmails.push({
          to: recipient.email,
          subject: rendered.subject,
          body: rendered.text,
          sentAt: message.sentAt,
        });
      }

      if (!result.success) {
        this.logger.error(`Failed to send email to ${recipient.email}: ${result.error}`);
        return { success: false, channel: 'email', error: result.error };
      }

      return { success: true, channel: 'email' };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Unexpected error sending email: ${errorMessage}`);
      return { success: false, channel: 'email', error: errorMessage };
    }
  }

  /**
   * Get all emails sent by this adapter (useful for testing).
   */
  getSentEmails(): Array<{ to: string; subject: string; body: string; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
