  describe('recipient resolution', () => {
    it('should reject empty recipient', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
      expect(transport.getMessages()).toHaveLength(0);
    });

    it('should reject invalid email format', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'not-an-email',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
      expect(transport.getMessages()).toHaveLength(0);
    });

    it('should trim whitespace from recipient', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '  alice@example.com  ',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getMessages()[0]?.to).toBe('alice@example.com');
    });
  });

  describe('transport error handling', () => {
    it('should return failed result when transport fails', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'SMTP connection refused' };
        },
      };

      const failAdapter = new EmailAdapter({ transport: failingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
      expect(failAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should catch transport exceptions and return failed result', async () => {
      const throwingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          throw new Error('Network timeout');
        },
      };

      const throwAdapter = new EmailAdapter({ transport: throwingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await throwAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });
  });

