      const customAdapter = new EmailAdapter({
        defaultFrom: 'support@taskflowpro.com',
        transport,
      });

      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
