    it('should clear sent email history', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome.',
      };

      await adapter.send(payload);
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('InMemoryTransport', () => {
    it('should store and return messages', async () => {
      const msg: EmailMessage = {
        from: 'a@b.com',
        to: 'c@d.com',
        subject: 'Test',
        html: '<p>Test</p>',
        text: 'Test',
        sentAt: new Date(),
      };

      const result = await transport.sendMail(msg);

      expect(result.success).toBe(true);
      expect(transport.getMessages()).toHaveLength(1);
      expect(transport.getMessages()[0]?.to).toBe('c@d.com');
    });

    it('should clear messages', async () => {
      const msg: EmailMessage = {
        from: 'a@b.com',
        to: 'c@d.com',
        subject: 'Test',
        html: '<p>Test</p>',
        text: 'Test',
        sentAt: new Date(),
      };

      await transport.sendMail(msg);
      transport.clear();
      expect(transport.getMessages()).toHaveLength(0);
    });
  });
